class AppDatabaseRouter:
    """
    A router to control all database operations on models in different apps.
    """

    app_to_db = {
        'base': 'base_db',
        'app1': 'app1_db',
        'app2': 'app2_db',
        # Add more app-to-database mappings as necessary
    }

    def db_for_read(self, model, **hints):
        """Point read operations for the model to the associated database."""
        return self.app_to_db.get(model._meta.app_label)

    def db_for_write(self, model, **hints):
        """Point write operations for the model to the associated database."""
        return self.app_to_db.get(model._meta.app_label)

    def allow_relation(self, obj1, obj2, **hints):
        """Allow relations if both models are in the same app."""
        db_obj1 = self.app_to_db.get(obj1._meta.app_label)
        db_obj2 = self.app_to_db.get(obj2._meta.app_label)
        if db_obj1 and db_obj2:
            return db_obj1 == db_obj2
        return None

    def allow_migrate(self, db, app_label, model_name=None, **hints):
        """Ensure that migrations are only applied to the app's database."""
        return self.app_to_db.get(app_label) == db
