import datetime

MONTHS = [
    'jan', 'feb', 'mar', 'apr', 'may', 'jun',
    'jul', 'aug', 'sep', 'oct', 'nov', 'dec'
]
WEEKDAYS = ['mon', 'tue', 'wed', 'thu', 'fri', 'sat', 'sun']

def parse_http_date(date):
    """
    Parses a date format as specified by HTTP to a datetime object.
    Date is returned in UTC.
    Return None if the input is invalid or cannot be parsed.
    """
    parts = date.split()

    if len(parts) == 3:
        # "Wed, 09 Feb 1994"
        return _parse_http_date_rfc850(parts)

    if len(parts) == 4 and parts[0][-1] == ',':
        # "Sun, 06 Nov 1994 08:49:37 GMT"
        return _parse_http_date_rfc1123(parts)

    if len(parts) == 5 and parts[0][-1] == ',':
        # "Sunday, 06-Nov-94 08:49:37 GMT"
        return _parse_http_date_rfc850(parts)

    return None

def _parse_http_date_rfc850(parts):
    """
    Parse a date in RFC 850 format: Sunday, 06-Nov-94 08:49:37 GMT
    """
    try:
        parts[1] = parts[1][:-1]

        day = int(parts[1].split('-')[0])
        month = MONTHS.index(parts[1].split('-')[1].lower()) + 1
        year = int(parts[1].split('-')[2])

        # Use the current year to calculate the cutoff for two-digit years
        current_year = datetime.datetime.utcnow().year
        current_century = current_year - (current_year % 100)

        # If the interpreted year is more than 50 years in the future, take it as the previous century
        if year > ((current_year - current_century) + 50):
            year += current_century - 100
        else:
            year += current_century
        hour, minute, second = map(int, parts[2].split(':'))
    except (IndexError, ValueError):
        return None

    try:
        return datetime.datetime(year, month, day, hour, minute, second, tzinfo=datetime.timezone.utc)
    except ValueError:
        return None

def _parse_http_date_rfc1123(parts):
    """
    Parse a date in RFC 1123 format: Sun, 06 Nov 1994 08:49:37 GMT
    """
    try:
        day = int(parts[1])
        month = MONTHS.index(parts[2].lower()) + 1
        year = int(parts[3])
        hour, minute, second = map(int, parts[4].split(':'))
    except (IndexError, ValueError):
        return None

    try:
        return datetime.datetime(year, month, day, hour, minute, second, tzinfo=datetime.timezone.utc)
    except ValueError:
        return None
```

This code snippet adjusts the two-digit year parsing in RFC 850 date formats to use the current year as a reference. Years with values that result in more than a 50-year difference to the future are interpreted as being in the past.

